// Define containers for automation (excluding critical Docker hosts)
const containers = [
  {id: '100', name: 'postoffice', critical: 'high'},
  {id: '105', name: 'authentik-proxy', critical: 'high'},
  {id: '107', name: 'npmplus', critical: 'medium'},
  {id: '108', name: 'bookstack', critical: 'low'},
  {id: '109', name: 'wazuh', critical: 'high'},
  {id: '115', name: 'stream', critical: 'low'},
  {id: '117', name: 'dev1rawgle', critical: 'low'},
  {id: '118', name: 'test-stack', critical: 'low'},
  {id: '119', name: 'jupyter-notebook', critical: 'low'},
  {id: '150', name: 'apt-cacher', critical: 'medium'}
];

const startTime = new Date();
const execution = {
  id: $execution.id,
  startTime: startTime.toISOString(),
  totalContainers: containers.length
};

console.log(`🚀 Starting Proxmox automation for ${containers.length} containers at ${startTime}`);
console.log('📦 Containers to process:', containers.map(c => `${c.id}:${c.name}`).join(', '));

return { containers, execution };

const container = $json.containers[$splitInBatches.index];
const success = $json.exitCode === 0;
const timestamp = new Date().toISOString();

if (success) {
  console.log(`✅ Container ${container.id} (${container.name}): Update completed successfully`);
} else {
  console.log(`❌ Container ${container.id} (${container.name}): Update failed with exit code ${$json.exitCode}`);
  console.log(`Error output: ${$json.stderr || 'No error details'}`);
}

return {
  container_id: container.id,
  container_name: container.name,
  status: success ? 'completed' : 'failed',
  success: success,
  timestamp: timestamp,
  exitCode: $json.exitCode,
  updatesApplied: parseInt($json.stdout?.match(/upgraded, (\d+)/)?.[1]) || 0,
  executionTime: Math.floor((new Date() - new Date($json.execution?.startTime || Date.now())) / 1000),
  output: $json.stdout?.substring(0, 500) || '',
  error: $json.stderr?.substring(0, 200) || ''
};

const container = $json.containers[$splitInBatches.index];
const timestamp = new Date().toISOString();
const isRunning = $json.stdout && $json.stdout.includes('status: running');
const hasUpdates = parseInt($json.stdout) > 0;

let reason, status;
if (!isRunning) {
  reason = 'Container not running';
  status = 'container_down';
  console.log(`⚠️ Container ${container.id} (${container.name}): Skipped - not running`);
} else if (!hasUpdates) {
  reason = 'No updates available';
  status = 'no_updates';
  console.log(`✅ Container ${container.id} (${container.name}): Up to date - no updates needed`);
} else {
  reason = 'Unknown';
  status = 'skipped';
  console.log(`ℹ️ Container ${container.id} (${container.name}): Skipped - ${reason}`);
}

return {
  container_id: container.id,
  container_name: container.name,
  status: status,
  success: null,
  timestamp: timestamp,
  reason: reason,
  availableUpdates: isRunning ? (parseInt($json.stdout) || 0) : null
};

// Generate comprehensive execution summary
const endTime = new Date();
const allResults = $input.all();
const startTime = new Date($input.first().json.execution?.startTime || Date.now());
const totalExecutionTime = Math.floor((endTime - startTime) / 1000);

// Categorize results
const successful = allResults.filter(item => item.json.success === true).length;
const failed = allResults.filter(item => item.json.success === false).length;
const noUpdates = allResults.filter(item => item.json.status === 'no_updates').length;
const containerDown = allResults.filter(item => item.json.status === 'container_down').length;
const skipped = allResults.filter(item => item.json.status === 'skipped').length;

// Calculate totals
const totalProcessed = allResults.length;
const totalUpdatesApplied = allResults.reduce((sum, item) => sum + (item.json.updatesApplied || 0), 0);

// Determine overall status
let overallStatus;
if (failed > 0) {
  overallStatus = failed === totalProcessed ? 'all_failed' : 'partial_failure';
} else if (successful > 0) {
  overallStatus = 'completed_with_updates';
} else {
  overallStatus = 'completed_no_updates';
}

const summary = {
  execution_date: endTime.toISOString().split('T')[0],
  execution_start: startTime.toISOString(),
  execution_end: endTime.toISOString(),
  total_execution_time: totalExecutionTime,
  total_containers: totalProcessed,
  successful_updates: successful,
  failed_updates: failed,
  no_updates_needed: noUpdates,
  containers_down: containerDown,
  other_skipped: skipped,
  total_packages_updated: totalUpdatesApplied,
  overall_status: overallStatus
};

// Log comprehensive summary
console.log('🎯 AUTOMATION EXECUTION SUMMARY');
console.log('================================');
console.log(`⏱️ Execution Time: ${totalExecutionTime} seconds`);
console.log(`📦 Total Containers: ${totalProcessed}`);
console.log(`✅ Successful Updates: ${successful}`);
console.log(`❌ Failed Updates: ${failed}`);
console.log(`ℹ️ No Updates Needed: ${noUpdates}`);
console.log(`⚠️ Containers Down: ${containerDown}`);
console.log(`🔧 Total Packages Updated: ${totalUpdatesApplied}`);
console.log(`🎯 Overall Status: ${overallStatus}`);

if (failed > 0) {
  console.log('❗ Failed Containers:');
  allResults.filter(item => item.json.success === false).forEach(item => {
    console.log(`  - ${item.json.container_id} (${item.json.container_name}): ${item.json.error || 'Unknown error'}`);
  });
}

return { summary, details: allResults };
